{"code": "import pandas as pd
import json
import re

# Load full data
tracks_file = locals().get('var_functions.query_db:6')
sales_file = locals().get('var_functions.query_db:7')

# Load tracks data
if tracks_file and isinstance(tracks_file, str) and tracks_file.endswith('.json'):
    with open(tracks_file, 'r') as f:
        tracks_data = json.load(f)
else:
    tracks_data = tracks_file

# Load sales data
if sales_file and isinstance(sales_file, str) and sales_file.endswith('.json'):
    with open(sales_file, 'r') as f:
        sales_data = json.load(f)
else:
    sales_data = sales_file

# Create DataFrames
tracks_df = pd.DataFrame(tracks_data)
sales_df = pd.DataFrame(sales_data)

# Data cleaning function
def clean_string(s):
    if not s or s.strip().lower() in ['none', '[unknown]', '']:
        return None
    return s.strip()

# Clean and normalize tracks data
tracks_df['title_clean'] = tracks_df['title'].apply(clean_string)
tracks_df['artist_clean'] = tracks_df['artist'].apply(clean_string)
tracks_df['album_clean'] = tracks_df['album'].apply(clean_string)

# Normalize year
def normalize_year(year):
    if not year or year.lower() in ['none', 'unk.']:
        return None

    # Extract 2 or 4 digit year from various formats
    year_str = str(year).strip()

    # Handle formats like '75', '05', '96
    if re.match(r"^'?\d{2}$", year_str):
        num = int(year_str.replace("'", ""))
        return 1900 + num if num > 20 else 2000 + num

    # Handle 4 digit years
    if re.match(r"^\d{4}$", year_str):
        return int(year_str)

    # Extract year from strings like "2010", "1998", etc.
    match = re.search(r"(\d{4})", year_str)
    if match:
        return int(match.group(1))

    return None

tracks_df['year_normalized'] = tracks_df['year'].apply(normalize_year)

print('__RESULT__:')
print(json.dumps({
    'cleaned_tracks_shape': tracks_df.shape,
    'missing_titles': tracks_df['title_clean'].isnull().sum(),
    'unique_titles': tracks_df['title_clean'].nunique(),
    'sample_cleaned': tracks_df[['track_id', 'title_clean', 'artist_clean', 'album_clean', 'year_normalized']].head(15).to_dict('records')
}))"}

